import React, { useEffect, useState } from "react";

function AdminDashboard() {
  const [data, setData] = useState([]);

  useEffect(() => {
    // Simulación de datos, luego puedes conectar al backend
    setData([{ nombre: "Producto 1" }, { nombre: "Producto 2" }]);
  }, []);

  return (
    <div style={{ padding: "2rem" }}>
      <h2>Panel de Administrador 🚀</h2>
      <ul>
        {data.map((item, index) => (
          <li key={index}>{item.nombre}</li>
        ))}
      </ul>
    </div>
  );
}

export default AdminDashboard; // 👈 Exportación por defecto obligatoria
